#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <semaphore.h>
#include <unistd.h>
#include <stdbool.h>

#define NUM_THREADS 4
#define QUEUE_SIZE 100

// Task structure
typedef struct {
 void (*function)(void*);
 void* argument;
} Task;

// Thread pool structure
typedef struct {
 Task queue[QUEUE_SIZE];
 int front;
 int rear;
 int count;

 pthread_mutex_t mutex;
 sem_t full; // Signals when queue has tasks
 sem_t empty; // Signals when queue has space

 pthread_t workers[NUM_THREADS];
 bool shutdown;
} ThreadPool;

// Initialize thread pool
void pool_init(ThreadPool* pool) {
 pool->front = 0;
 pool->rear = 0;
 pool->count = 0;
 pool->shutdown = false;

 pthread_mutex_init(&pool->mutex, NULL);
 sem_init(&pool->full, 0, 0);
 sem_init(&pool->empty, 0, QUEUE_SIZE);

 // Create worker threads
 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_create(&pool->workers[i], NULL, worker_thread, pool);
 }
}

// Worker function that processes tasks from queue
void* worker_thread(void* arg) {
 ThreadPool* pool = (ThreadPool*)arg;

 while (true) {
 // Wait for task to be available
 sem_wait(&pool->full);

 pthread_mutex_lock(&pool->mutex);

 // Check shutdown flag
 if (pool->shutdown) {
 pthread_mutex_unlock(&pool->mutex);
 break;
 }

 // Get task from queue
 Task task = pool->queue[pool->front];
 pool->front = (pool->front + 1) % QUEUE_SIZE;
 pool->count--;

 pthread_mutex_unlock(&pool->mutex);
 sem_post(&pool->empty); // Signal that queue has space

 // Execute the task
 task.function(task.argument);
 }

 return NULL;
}

// Submit task to pool
void pool_submit(ThreadPool* pool, void (*function)(void*), void* arg) {
 sem_wait(&pool->empty); // Wait for space in queue

 pthread_mutex_lock(&pool->mutex);

 Task task;
 task.function = function;
 task.argument = arg;

 pool->queue[pool->rear] = task;
 pool->rear = (pool->rear + 1) % QUEUE_SIZE;
 pool->count++;

 pthread_mutex_unlock(&pool->mutex);
 sem_post(&pool->full); // Signal that task is available
}

// Shutdown thread pool
void pool_shutdown(ThreadPool* pool) {
 pool->shutdown = true;

 // Wake up all worker threads
 for (int i = 0; i < NUM_THREADS; i++) {
 sem_post(&pool->full);
 }

 // Wait for all workers to finish
 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_join(pool->workers[i], NULL);
 }

 pthread_mutex_destroy(&pool->mutex);
 sem_destroy(&pool->full);
 sem_destroy(&pool->empty);
}

// Example task functions
void print_number(void* arg) {
 int num = *(int*)arg;
 printf("Task %d processed by thread %lu\n", 
 num, pthread_self() % 100);
 sleep(1); // Simulate work
}

int main() {
 ThreadPool pool;
 pool_init(&pool);

 printf("Thread pool with %d workers created.\n", NUM_THREADS);
 printf("Submitting 8 tasks...\n\n");

 // Submit tasks
 for (int i = 0; i < 8; i++) {
 int* task_num = malloc(sizeof(int));
 *task_num = i;
 pool_submit(&pool, print_number, task_num);
 }

 // Wait for tasks to complete
 sleep(10);

 printf("\nShutting down thread pool...\n");
 pool_shutdown(&pool);

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <string.h>

// Define a key for thread-specific data
pthread_key_t transaction_key;
pthread_key_t thread_name_key;

// Structure to hold thread-specific data
typedef struct {
 int transaction_id;
 int request_count;
} ThreadData;

// Cleanup function called when thread exits
void cleanup_thread_data(void* data) {
 printf("[CLEANUP] Freeing thread data for thread %lu\n", 
 pthread_self() % 100);
 free(data);
}

// Worker thread function
void* worker_thread(void* arg) {
 int thread_num = *(int*)arg;

 // Allocate thread-specific data
 ThreadData* my_data = (ThreadData*)malloc(sizeof(ThreadData));
 my_data->transaction_id = 1000 + thread_num;
 my_data->request_count = 0;

 // Set thread-specific data using the key
 pthread_setspecific(transaction_key, my_data);

 // Also set thread name
 char* name = (char*)malloc(20);
 sprintf(name, "Worker-%d", thread_num);
 pthread_setspecific(thread_name_key, name);

 printf("[START] Thread %s initialized with Transaction ID: %d\n",
 (char*)pthread_getspecific(thread_name_key),
 ((ThreadData*)pthread_getspecific(transaction_key))->transaction_id);

 // Process multiple requests
 for (int i = 0; i < 3; i++) {
 // Get thread-specific data
 ThreadData* data = (ThreadData*)pthread_getspecific(transaction_key);
 data->request_count++;

 char* name = (char*)pthread_getspecific(thread_name_key);
 printf("[REQUEST] %s: Transaction %d, Request #%d\n",
 name, data->transaction_id, data->request_count);
 }

 printf("[END] Thread %s completed %d requests\n",
 (char*)pthread_getspecific(thread_name_key),
 ((ThreadData*)pthread_getspecific(transaction_key))->request_count);

 return NULL;
}

int main() {
 pthread_t threads[3];
 int thread_args[3];

 // Create key for thread-specific transaction data with cleanup
 if (pthread_key_create(&transaction_key, cleanup_thread_data) != 0) {
 perror("pthread_key_create failed");
 return 1;
 }

 // Create key for thread name
 if (pthread_key_create(&thread_name_key, free) != 0) {
 perror("pthread_key_create failed");
 return 1;
 }

 printf("=== Thread-Specific Data Demo ===\n\n");

 // Create worker threads
 for (int i = 0; i < 3; i++) {
 thread_args[i] = i;
 pthread_create(&threads[i], NULL, worker_thread, &thread_args[i]);
 }

 // Wait for all threads to complete
 for (int i = 0; i < 3; i++) {
 pthread_join(threads[i], NULL);
 }

 printf("\n=== All threads completed ===\n");
 printf("Each thread maintained its own Transaction ID.\n");

 // Destroy keys
 pthread_key_delete(transaction_key);
 pthread_key_delete(thread_name_key);

 return 0;
}
